1	import {
2	  createUser as createUserHelper,
3	  deleteUser as deleteUserHelper,
4	  getAllUsers,
5	  handleAllUsersRequest,
6	  handleCashiersRequest,
7	  handleDeletedUsersRequest,
8	  updateUser as updateUserHelper,
9	} from '@/app/api/lib/helpers/users/users';
10	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
11	import {
12	  validateEmail,
13	  validatePasswordStrength,
14	} from '@/lib/utils/validation';
15	import { NextRequest, NextResponse } from 'next/server';
16	import { apiLogger } from '../lib/services/loggerService';
17	import {
18	  logRouteFetch,
19	  logRouteCreate,
20	  logRouteUpdate,
21	  logRouteDelete,
22	  logRouteError,
23	  extractUserFromRequest,
24	} from '@/app/api/lib/utils/routeLogger';
25	
26	/**
27	 * Main GET handler for fetching users
28	 *
29	 * @param {string} status - Filter by status ('deleted', 'all')
30	 * @param {string} role - Filter by role (e.g., 'cashier')
31	 * @param {string} licencee - Filter users by assigned licencee ID
32	 * @param {string} search - Search query for username or profile name
33	 * @param {number} page - Page number for pagination
34	 * @param {number} limit - Items per page
35	 */
36	export async function GET(request: NextRequest) {
37	  return withApiAuth(
38	    request,
39	    async ({ user: currentUser, userRoles, isAdminOrDev }) => {
40	      const startTime = Date.now();
41	      const functionName = 'GET /api/users';
42	      const user = extractUserFromRequest(request);
43	      const context = apiLogger.createContext(request, '/api/users');
44	      apiLogger.startLogging();
45	
46	      // ============================================================================
47	      // STEP 1: Process User Permissions
48	      // ============================================================================
49	
50	      // Check if the assignedLicencees field exists and is a valid array
51	      const currentUserLicencees = Array.isArray(currentUser?.assignedLicencees)
52	        ? currentUser.assignedLicencees
53	        : [];
54	
55	      // Check if the assignedLocations field exists and is a valid array
56	      const currentUserLocationPermissions = Array.isArray(
57	        currentUser?.assignedLocations
58	      )
59	        ? (currentUser.assignedLocations as unknown[]).map(id => String(id))
60	        : [];
61	
62	      const isManager = userRoles.includes('manager') && !isAdminOrDev;
63	      const isLocationAdmin =
64	        userRoles.includes('location admin') && !isAdminOrDev && !isManager;
65	      const isVaultManager =
66	        userRoles.includes('vault-manager') && !isAdminOrDev && !isManager;
67	
68	      // ============================================================================
69	      // STEP 2: Parse query parameters
70	      // ============================================================================
71	      const { searchParams } = new URL(request.url);
72	      const status = searchParams.get('status') || 'all';
73	      const role = searchParams.get('role');
74	
75	      if (!getAllUsers) {
76	        logRouteError(
77	          functionName,
78	          'GET',
79	          '/api/users',
80	          'Service not available',
81	          user
82	        );
83	        return NextResponse.json(
84	          { success: false, message: 'Service not available' },
85	          { status: 500 }
86	        );
87	      }
88	
89	      // ============================================================================
90	      // STEP 3: Handle request based on status/role filters
91	      // ============================================================================
92	      // PURPOSE: Get deleted users
93	      if (status === 'deleted') {
94	        if (!isAdminOrDev && !isManager && !isLocationAdmin) {
95	          logRouteError(
96	            functionName,
97	            'GET',
98	            '/api/users',
99	            'Access denied',
100	            user
101	          );
102	          return NextResponse.json(
103	            { success: false, message: 'Access denied' },
104	            { status: 403 }
105	          );
106	        }
107	        const result = await handleDeletedUsersRequest(
108	          currentUser,
109	          userRoles,
110	          currentUserLicencees,
111	          currentUserLocationPermissions,
112	          searchParams,
113	          startTime,
114	          context
115	        );
116	        const duration = Date.now() - startTime;
117	        logRouteFetch(functionName, 'GET', '/api/users', 1, user, duration);
118	        return result;
119	      }
120	
121	      // PURPOSE: Get cashiers only
122	      if (role === 'cashier') {
123	        if (
124	          !isAdminOrDev &&
125	          !isManager &&
126	          !isVaultManager &&
127	          !isLocationAdmin
128	        ) {
129	          logRouteError(
130	            functionName,
131	            'GET',
132	            '/api/users',
133	            'Access denied - only admins, managers, and vault managers can access cashiers',
134	            user
135	          );
136	          return NextResponse.json(
137	            {
138	              success: false,
139	              message:
140	                'Access denied - only admins, managers, and vault managers can access cashiers',
141	            },
142	            { status: 403 }
143	          );
144	        }
145	        const result = await handleCashiersRequest(
146	          currentUser,
147	          userRoles,
148	          currentUserLicencees,
149	          currentUserLocationPermissions,
150	          searchParams,
151	          startTime,
152	          context
153	        );
154	        const duration = Date.now() - startTime;
155	        logRouteFetch(functionName, 'GET', '/api/users', 1, user, duration);
156	        return result;
157	      }
158	
159	      // PURPOSE: Get all users (default case)
160	      const result = await handleAllUsersRequest(
161	        currentUser,
162	        userRoles,
163	        currentUserLicencees,
164	        currentUserLocationPermissions,
165	        searchParams,
166	        startTime,
167	        context
168	      );
169	      const duration = Date.now() - startTime;
170	      logRouteFetch(functionName, 'GET', '/api/users', 1, user, duration);
171	      return result;
172	    }
173	  );
174	}
