176	/**
177	 * Main POST handler for creating a new user
178	 */
179	export async function POST(request: NextRequest) {
180	  return withApiAuth(request, async () => {
181	    const startTime = Date.now();
182	    const functionName = 'POST /api/users';
183	    const user = extractUserFromRequest(request);
184	
185	    // ============================================================================
186	    // STEP 1: Parse request body
187	    // ============================================================================
188	    const body = await request.json();
189	
190	    const {
191	      username,
192	      emailAddress,
193	      password,
194	      roles = [],
195	      profile = {},
196	      isEnabled = true,
197	      profilePicture = null,
198	      assignedLocations,
199	      assignedLicencees,
200	      tempPassword,
201	      moneyInMultiplier,
202	      moneyOutAndJackpotMultiplier,
203	      reviewerMultiplierStartTime,
204	    } = body;
205	
206	    // ============================================================================
207	    // STEP 2: Validate required fields and constraints
208	    // ============================================================================
209	    if (!username || typeof username !== 'string') {
210	      logRouteError(
211	        functionName,
212	        'POST',
213	        '/api/users',
214	        'Username is required',
215	        user
216	      );
217	      return NextResponse.json(
218	        { success: false, message: 'Username is required' },
219	        { status: 400 }
220	      );
221	    }
222	
223	    if (!emailAddress || !validateEmail(emailAddress)) {
224	      logRouteError(
225	        functionName,
226	        'POST',
227	        '/api/users',
228	        'Valid email is required',
229	        user
230	      );
231	      return NextResponse.json(
232	        { success: false, message: 'Valid email is required' },
233	        { status: 400 }
234	      );
235	    }
236	
237	    if (!profile || !profile.gender) {
238	      logRouteError(
239	        functionName,
240	        'POST',
241	        '/api/users',
242	        'Gender is required',
243	        user
244	      );
245	      return NextResponse.json(
246	        { success: false, message: 'Gender is required' },
247	        { status: 400 }
248	      );
249	    }
250	
251	    if (!password) {
252	      logRouteError(
253	        functionName,
254	        'POST',
255	        '/api/users',
256	        'Password is required',
257	        user
258	      );
259	      return NextResponse.json(
260	        { success: false, message: 'Password is required' },
261	        { status: 400 }
262	      );
263	    }
264	
265	    const passwordValidation = validatePasswordStrength(password);
266	    if (!passwordValidation.isValid) {
267	      logRouteError(
268	        functionName,
269	        'POST',
270	        '/api/users',
271	        `Password requirements not met: ${passwordValidation.feedback.join(', ')}`,
272	        user
273	      );
274	      return NextResponse.json(
275	        {
276	          success: false,
277	          message: `Password requirements not met: ${passwordValidation.feedback.join(', ')}`,
278	        },
279	        { status: 400 }
280	      );
281	    }
282	
283	    // ============================================================================
284	    // STEP 3: Create User and handle response
285	    // ============================================================================
286	    try {
287	      const userWithoutPassword = await createUserHelper(
288	        {
289	          username,
290	          emailAddress,
291	          password,
292	          roles,
293	          profile,
294	          isEnabled,
295	          profilePicture,
296	          assignedLocations,
297	          assignedLicencees,
298	          tempPassword,
299	          moneyInMultiplier,
300	          moneyOutAndJackpotMultiplier,
301	          reviewerMultiplierStartTime,
302	        },
303	        request
304	      );
305	
306	      const duration = Date.now() - startTime;
307	      logRouteCreate(functionName, 'POST', '/api/users', 1, user, duration);
308	      return NextResponse.json(
309	        { success: true, user: userWithoutPassword },
310	        { status: 201 }
311	      );
312	    } catch (err: unknown) {
313	      const errorMsg = err instanceof Error ? err.message : 'Unknown error';
314	      const isConflictError = errorMsg.includes('already exists');
315	      logRouteError(functionName, 'POST', '/api/users', errorMsg, user);
316	      return NextResponse.json(
317	        {
318	          success: false,
319	          message: isConflictError ? errorMsg : 'User creation failed',
320	          error: errorMsg,
321	        },
322	        { status: isConflictError ? 409 : 500 }
323	      );
324	    }
325	  });
326	}
