328	/**
329	 * Main PUT handler for updating a user
330	 */
331	export async function PUT(request: NextRequest) {
332	  return withApiAuth(request, async () => {
333	    const startTime = Date.now();
334	    const functionName = 'PUT /api/users';
335	    const user = extractUserFromRequest(request);
336	
337	    // ============================================================================
338	    // STEP 1: Parse request body
339	    // ============================================================================
340	    const body = await request.json();
341	    const { _id, ...updateFields } = body;
342	
343	    // ============================================================================
344	    // STEP 2: Validate ID
345	    // ============================================================================
346	    if (!_id) {
347	      logRouteError(
348	        functionName,
349	        'PUT',
350	        '/api/users',
351	        'User ID is required',
352	        user
353	      );
354	      return NextResponse.json(
355	        { success: false, message: 'User ID is required' },
356	        { status: 400 }
357	      );
358	    }
359	
360	    // ============================================================================
361	    // STEP 3: Process update
362	    // ============================================================================
363	    try {
364	      const updatedUser = await updateUserHelper(_id, updateFields, request);
365	      const userObject = updatedUser.toObject
366	        ? updatedUser.toObject()
367	        : updatedUser;
368	
369	      const formattedUser = {
370	        ...userObject,
371	        assignedLocations: userObject.assignedLocations || undefined,
372	        assignedLicencees: userObject.assignedLicencees || undefined,
373	      };
374	
375	      const duration = Date.now() - startTime;
376	      logRouteUpdate(functionName, 'PUT', '/api/users', 1, user, duration);
377	      return NextResponse.json({ success: true, user: formattedUser });
378	    } catch (err: unknown) {
379	      const errorMsg = err instanceof Error ? err.message : 'Unknown error';
380	      const isConflictError = errorMsg.includes('already exists');
381	      const isNotFoundError = errorMsg === 'User not found';
382	      logRouteError(functionName, 'PUT', '/api/users', errorMsg, user);
383	
384	      return NextResponse.json(
385	        {
386	          success: false,
387	          message:
388	            isNotFoundError || isConflictError ? errorMsg : 'Update failed',
389	          error: errorMsg,
390	        },
391	        { status: isNotFoundError ? 404 : isConflictError ? 409 : 500 }
392	      );
393	    }
394	  });
395	}
