442	      return NextResponse.json(
443	        {
444	          success: false,
445	          message: isNotFoundError ? errorMsg : 'Delete failed',
446	          error: errorMsg,
447	        },
448	        { status: isNotFoundError ? 404 : 500 }
449	      );
450	    }
451	  });
