1	/**
2	 * User by ID API Route
3	 *
4	 * This route handles fetching, updating, and deleting individual users by ID.
5	 * It supports:
6	 * - Fetching user data by ID
7	 * - Updating user information
8	 * - API logging for all operations
9	 *
10	 * @module app/api/users/[id]/route
11	 */
12	
13	import {
14	  getUserById,
15	  updateUser as updateUserHelper,
16	} from '@/app/api/lib/helpers/users';
17	import { connectDB } from '@/app/api/lib/middleware/db';
18	import { NextRequest, NextResponse } from 'next/server';
19	import { apiLogger } from '../../lib/services/loggerService';
20	import {
21	  logRouteFetch,
22	  logRouteUpdate,
23	  logRouteError,
24	  extractUserFromRequest,
25	} from '@/app/api/lib/utils/routeLogger';
26	
27	/**
28	 * GET /api/users/[id]
29	 *
30	 * Fetches a single user document by ID for the Users management page.
31	 *
32	 * URL params:
33	 * @param id {string} Required (path). The string `_id` of the user to retrieve.
34	 */
35	export async function GET(request: NextRequest): Promise<Response> {
36	  const startTime = Date.now();
37	  const functionName = 'GET /api/users/[id]';
38	  const logUser = extractUserFromRequest(request);
39	  const { pathname } = request.nextUrl;
40	  const userId = pathname.split('/').pop();
41	  const context = apiLogger.createContext(request, `/api/users/${userId}`);
42	  apiLogger.startLogging();
43	
44	  try {
45	    // ============================================================================
46	    // STEP 1: Connect to database
47	    // ============================================================================
48	    await connectDB();
49	
50	    // ============================================================================
51	    // STEP 2: Validate user ID
52	    // ============================================================================
53	
54	    if (!userId) {
55	      apiLogger.logError(context, 'User fetch failed', 'User ID is required');
56	      return NextResponse.json(
57	        { success: false, message: 'User ID is required' },
58	        { status: 400 }
59	      );
60	    }
61	
62	    // ============================================================================
63	    // STEP 3: Fetch user from database
64	    // ============================================================================
65	    const user = await getUserById(userId);
66	    if (!user) {
67	      apiLogger.logError(context, 'User fetch failed', 'User not found');
68	      return NextResponse.json(
69	        { success: false, message: 'User not found' },
70	        { status: 404 }
71	      );
72	    }
73	
74	    // ============================================================================
75	    // STEP 4: Format user data
76	    // ============================================================================
77	    if (Array.isArray(user)) {
78	      return NextResponse.json({ error: 'User not found' }, { status: 404 });
79	    }
80	    const formattedUser = {
81	      ...user,
82	    };
83	
84	    // ============================================================================
85	    // STEP 5: Return user data
86	    // ============================================================================
87	    const duration = Date.now() - startTime;
88	    if (duration > 1000) {
89	      console.warn(`[Users API] GET completed in ${duration}ms`);
90	    }
91	
92	    logRouteFetch(
93	      functionName,
94	      'GET',
95	      `/api/users/${userId}`,
96	      1,
97	      logUser,
98	      duration
99	    );
100	    apiLogger.logSuccess(context, `Successfully fetched user ${userId}`);
101	    return NextResponse.json({ success: true, user: formattedUser });
102	  } catch (err: unknown) {
103	    const duration = Date.now() - startTime;
104	    const errorMsg = err instanceof Error ? err.message : 'Unknown error';
105	    console.error(`[Users API] GET error after ${duration}ms:`, errorMsg);
106	    logRouteError(
107	      functionName,
108	      'GET',
109	      `/api/users/${userId}`,
110	      errorMsg,
111	      logUser
112	    );
113	    apiLogger.logError(context, 'User fetch failed', errorMsg);
114	    return NextResponse.json(
115	      {
116	        success: false,
117	        message:
118	          errorMsg === 'User not found' ? errorMsg : 'Failed to fetch user',
119	        error: errorMsg,
120	      },
121	      { status: errorMsg === 'User not found' ? 404 : 500 }
122	    );
123	  }
124	}
