126	/**
127	 * PUT /api/users/[id]
128	 *
129	 * Performs a full replacement update of a user record; used by the Users management
130	 * page to save changes to profile, roles, and access assignments. `_id` is stripped
131	 * from the body before the update is applied so the path param is always authoritative.
132	 *
133	 * URL params:
134	 * @param id {string} Required (path). The string `_id` of the user to update.
135	 *
136	 * Body fields:
137	 * @param _id              {string}   Ignored. Stripped before update; the path `id` is used instead.
138	 * @param roles            {string[]} Optional. New role list for the user (e.g. `["manager", "collector"]`).
139	 *                                    Triggers `sessionVersion` increment to force re-login.
140	 * @param assignedLocations  {string[]} Optional. Location IDs the user is permitted to access.
141	 *                                    Restricted to admin/owner/developer; silently stripped for others.
142	 * @param assignedLicencees  {string[]} Optional. Licencee IDs that scope the user's data visibility.
143	 *                                    Restricted to admin/owner/developer; silently stripped for others.
144	 * @param isEnabled        {boolean}  Optional. Activates or deactivates the user account.
145	 * @param moneyInMultiplier {number}   Optional. Money-in reduction (reviewer role only).
146	 *                                    Restricted to admin/owner/developer; silently stripped for others.
147	 * @param moneyOutAndJackpotMultiplier {number} Optional. Money-out/jackpot reduction (reviewer role only).
148	 *                                    Restricted to admin/owner/developer; silently stripped for others.
149	 * @param reviewerMultiplierStartTime {string|Date} Optional. Start date/time from which reviewer multipliers apply.
150	 *                                    Restricted to admin/owner/developer; silently stripped for others.
151	 * @param profile          {object}   Optional. Nested profile fields: `firstName`, `lastName`,
152	 *                                    `gender`, `phoneNumber`, `identification` (idType/idNumber).
153	 * @param username         {string}   Optional. Login username; must be unique across all users.
154	 * @param emailAddress     {string}   Optional. Login email; must be unique across all users.
155	 * @param password         {string}   Optional. New plain-text password; hashed before storage.
156	 */
157	export async function PUT(request: NextRequest): Promise<Response> {
158	  const startTime = Date.now();
159	  const functionName = 'PUT /api/users/[id]';
160	  const user = extractUserFromRequest(request);
161	  const { pathname } = request.nextUrl;
162	  const userId = pathname.split('/').pop();
163	  const context = apiLogger.createContext(request, `/api/users/${userId}`);
164	  apiLogger.startLogging();
165	
166	  try {
167	    // ============================================================================
168	    // STEP 1: Connect to database
169	    // ============================================================================
170	    await connectDB();
171	
172	    // ============================================================================
173	    // STEP 2: Parse request body
174	    // ============================================================================
175	    const body = await request.json();
176	    const { _id, ...updateFields } = body;
177	
178	    // ============================================================================
179	    // STEP 3: Validate user ID
180	    // ============================================================================
181	    // Use the ID from the URL parameter
182	
183	    if (!userId) {
184	      apiLogger.logError(context, 'User update failed', 'User ID is required');
185	      return NextResponse.json(
186	        { success: false, message: 'User ID is required' },
187	        { status: 400 }
188	      );
189	    }
190	
191	    // ============================================================================
192	    // STEP 4: Update user in database
193	    // ============================================================================
194	    const updatedUser = await updateUserHelper(userId, updateFields, request);
195	
196	    // ============================================================================
197	    // STEP 5: Convert Mongoose document to plain object
198	    // ============================================================================
199	    const userObject = updatedUser.toObject
200	      ? updatedUser.toObject({ virtuals: false, getters: true })
201	      : updatedUser;
202	
203	    const formattedUser = {
204	      ...userObject,
205	    };
206	
207	    // ============================================================================
208	    // STEP 6: Return updated user data
209	    // ============================================================================
210	    const duration = Date.now() - startTime;
211	    if (duration > 1000) {
212	      console.warn(`[Users API] PUT completed in ${duration}ms`);
213	    }
214	
215	    logRouteUpdate(
216	      functionName,
217	      'PUT',
218	      `/api/users/${userId}`,
219	      1,
220	      user,
221	      duration
222	    );
223	    apiLogger.logSuccess(context, `Successfully updated user ${userId}`);
224	    return NextResponse.json({ success: true, user: formattedUser });
225	  } catch (err: unknown) {
226	    const duration = Date.now() - startTime;
227	    const errorMsg = err instanceof Error ? err.message : 'Unknown error';
228	    console.error(`[Users API] PUT error after ${duration}ms:`, errorMsg);
229	    logRouteError(functionName, 'PUT', `/api/users/${userId}`, errorMsg, user);
230	    apiLogger.logError(context, 'User update failed', errorMsg);
231	    return NextResponse.json(
232	      {
233	        success: false,
234	        message: errorMsg === 'User not found' ? errorMsg : 'Update failed',
235	        error: errorMsg,
236	      },
237	      { status: errorMsg === 'User not found' ? 404 : 500 }
238	    );
239	  }
240	}
