273	export async function PATCH(request: NextRequest): Promise<Response> {
274	  const startTime = Date.now();
275	  const functionName = 'PATCH /api/users/[id]';
276	  const user = extractUserFromRequest(request);
277	  const { pathname } = request.nextUrl;
278	  const userId = pathname.split('/').pop();
279	  const context = apiLogger.createContext(request, `/api/users/${userId}`);
280	  apiLogger.startLogging();
281	
282	  try {
283	    // ============================================================================
284	    // STEP 1: Connect to database
285	    // ============================================================================
286	    await connectDB();
287	
288	    // ============================================================================
289	    // STEP 2: Parse request body
290	    // ============================================================================
291	    const body = await request.json();
292	    const { _id, ...updateFields } = body;
293	
294	    // ============================================================================
295	    // STEP 3: Validate user ID
296	    // ============================================================================
297	    // Use the ID from the URL parameter
298	
299	    if (!userId) {
300	      apiLogger.logError(context, 'User update failed', 'User ID is required');
301	      return NextResponse.json(
302	        { success: false, message: 'User ID is required' },
303	        { status: 400 }
304	      );
305	    }
306	
307	    // ============================================================================
308	    // STEP 4: Update user in database
309	    // ============================================================================
310	    const updatedUser = await updateUserHelper(userId, updateFields, request);
311	
312	    // ============================================================================
313	    // STEP 5: Convert Mongoose document to plain object
314	    // ============================================================================
315	    const userObject = updatedUser.toObject
316	      ? updatedUser.toObject({ virtuals: false, getters: true })
317	      : updatedUser;
318	
319	    const formattedUser = {
320	      ...userObject,
321	    };
322	
323	    // ============================================================================
324	    // STEP 6: Return updated user data
325	    // ============================================================================
326	    const duration = Date.now() - startTime;
327	    if (duration > 1000) {
328	      console.warn(`[Users API] PATCH completed in ${duration}ms`);
329	    }
330	
331	    logRouteUpdate(
332	      functionName,
333	      'PATCH',
334	      `/api/users/${userId}`,
335	      1,
336	      user,
337	      duration
338	    );
339	    apiLogger.logSuccess(context, `Successfully updated user ${userId}`);
340	    return NextResponse.json({ success: true, user: formattedUser });
341	  } catch (err: unknown) {
342	    const duration = Date.now() - startTime;
343	    const errorMsg = err instanceof Error ? err.message : 'Unknown error';
344	    console.error(`[Users API] PATCH error after ${duration}ms:`, errorMsg);
345	    logRouteError(
346	      functionName,
347	      'PATCH',
348	      `/api/users/${userId}`,
349	      errorMsg,
350	      user
351	    );
352	    apiLogger.logError(context, 'User update failed', errorMsg);
353	    return NextResponse.json(
354	      {
355	        success: false,
356	        message: errorMsg === 'User not found' ? errorMsg : 'Update failed',
357	        error: errorMsg,
358	      },
359	      { status: errorMsg === 'User not found' ? 404 : 500 }
