54	export async function GET(request: NextRequest) {
55	  return withApiAuth(request, async () => {
56	    const startTime = Date.now();
57	    const functionName = 'GET /api/licencees';
58	    const user = extractUserFromRequest(request);
59	    const { searchParams } = new URL(request.url);
60	    const licenceeFilter = searchParams.get('licencee');
61	
62	    const userLicenceeAccess = await getUserAccessibleLicenceesFromToken();
63	    const licencees = await getAllLicencees();
64	    let formattedLicencees = (await formatLicenceesForResponse(
65	      licencees
66	    )) as unknown as Array<
67	      { _id: string; name: string } & Record<string, unknown>
68	    >;
69	
70	    if (userLicenceeAccess !== 'all') {
71	      const allowedIds = new Set(
72	        userLicenceeAccess.map(value => value.toString())
73	      );
74	      formattedLicencees = formattedLicencees.filter(licencee => {
75	        const licenceeId = licencee._id;
76	        return licenceeId && allowedIds.has(String(licenceeId));
77	      });
78	    }
79	
80	    if (licenceeFilter && licenceeFilter !== 'all') {
81	      formattedLicencees = formattedLicencees.filter(licencee => {
82	        const licenceeId = licencee._id;
83	        const licenceeName = licencee.name;
84	        return licenceeId === licenceeFilter || licenceeName === licenceeFilter;
85	      });
86	    }
87	
88	    const page = parseInt(searchParams.get('page') || '1');
89	    const requestedLimit = parseInt(searchParams.get('limit') || '50');
90	    const limit = Math.min(requestedLimit, 100);
91	    const skip = (page - 1) * limit;
92	
93	    const totalCount = formattedLicencees.length;
94	    const paginatedLicencees = formattedLicencees.slice(skip, skip + limit);
95	
96	    const duration = Date.now() - startTime;
97	    logRouteFetch(
98	      functionName,
99	      'GET',
100	      '/api/licencees',
101	      paginatedLicencees.length,
102	      user,
103	      duration
104	    );
105	
106	    return NextResponse.json({
107	      licencees: paginatedLicencees,
108	      pagination: {
109	        page,
110	        limit,
111	        total: totalCount,
112	        totalPages: Math.ceil(totalCount / limit),
113	      },
114	    });
115	  });
116	}
