1	import { NextResponse, NextRequest } from 'next/server';
2	import { connectDB } from '@/app/api/lib/middleware/db';
3	import { getUserFromServer } from '@/app/api/lib/helpers/users/users';
4	
5	/**
6	 * Common API Response Types
7	 */
8	export type ApiResponse<T = unknown> = {
9	  success: boolean;
10	  data?: T;
11	  error?: string;
12	  [key: string]: unknown;
13	};
14	
15	import { mongo } from 'mongoose';
16	
17	/**
18	 * Standard Auth Data returned by the wrapper
19	 */
20	export type ApiAuthContext = {
21	  user: {
22	    _id: string;
23	    username?: string;
24	    emailAddress?: string;
25	    roles?: string[];
26	    assignedLicencees?: string[];
27	    assignedLocations?: string[];
28	    [key: string]: unknown;
29	  };
30	  userRoles: string[];
31	  isAdminOrDev: boolean;
32	  db?: mongo.Db;
33	};
34	
35	/**
36	 * Higher-order function to wrap API route handlers with common logic
37	 * Handles database connection, authentication, and standardized error responses.
38	 */
39	export async function withApiAuth(
40	  req: NextRequest,
41	  handler: (context: ApiAuthContext) => Promise<NextResponse>,
42	  options: {
43	    optionalAuth?: boolean;
44	    bypassDb?: boolean;
45	  } = {}
46	): Promise<NextResponse> {
47	  if (!req || !handler) {
48	    console.error('[withApiAuth] req and handler are required');
49	    return NextResponse.json(
50	      { success: false, error: 'Missing required parameters' },
51	      { status: 400 }
52	    );
53	  }
54	  try {
55	    // 1. Connect to Database (unless bypassed)
56	    let db: mongo.Db | undefined;
57	
58	    if (!options.bypassDb) {
59	      db = await connectDB();
60	      if (!db) {
61	        return NextResponse.json(
62	          { success: false, error: 'Database connection failed' },
63	          { status: 500 }
64	        );
65	      }
66	    }
67	
68	    // 2. Authenticate User
69	    const userPayload = await getUserFromServer();
70	
71	    // If not public and no user, return 401
72	    if (!userPayload && !options.optionalAuth) {
73	      return NextResponse.json(
74	        { success: false, error: 'Unauthorized' },
75	        { status: 401 }
76	      );
77	    }
78	
79	    const userRoles = (userPayload?.roles as string[]) || [];
80	    const isAdminOrDev =
81	      userRoles.includes('admin') ||
82	      userRoles.includes('developer') ||
83	      userRoles.includes('owner');
84	
85	    // 3. Execute Handler
86	    return await handler({
87	      user: userPayload as ApiAuthContext['user'],
88	      userRoles,
89	      isAdminOrDev,
90	      db,
91	    });
92	  } catch (error) {
93	    const message =
94	      error instanceof Error ? error.message : 'Internal Server Error';
95	    console.error('[withApiAuth] Error:', message);
96	    return NextResponse.json(
97	      { success: false, error: message },
98	      { status: 500 }
99	    );
100	  }
101	}
