63	        JSON.stringify({ success: false, message: 'Unauthorized' }),
64	        { status: 401 }
65	      );
66	    }
67	
68	    const currentUserRoles = (currentUser.roles as string[]) || [];
69	    const isAdmin =
70	      currentUserRoles.includes('admin') ||
71	      currentUserRoles.includes('developer') ||
72	      currentUserRoles.includes('owner');
73	    const isManager = currentUserRoles.includes('manager') && !isAdmin;
74	    const isLocationAdmin =
75	      currentUserRoles.includes('location admin') && !isAdmin && !isManager;
76	
77	    let currentUserLicencees: string[] = [];
78	    if (
79	      Array.isArray(
80	        (currentUser as { assignedLicencees?: string[] })?.assignedLicencees
81	      )
82	    ) {
83	      currentUserLicencees = (currentUser as { assignedLicencees: string[] })
84	        .assignedLicencees;
85	    }
86	
87	    // ============================================================================
88	    // STEP 3: Parse query parameters
89	    // ============================================================================
90	    const { searchParams } = new URL(request.url);
91	    const licencee = searchParams.get('licencee');
92	
93	    // ============================================================================
94	    // STEP 4: Fetch all users (excludes deletedAt >= 2025-01-01)
95	    // ============================================================================
96	    const allUsers = await getAllUsers();
97	
98	    // ============================================================================
99	    // STEP 5: Apply role-based filtering (Manager, Location Admin)
100	    // ============================================================================
101	    let filteredUsers = allUsers;
102	
103	    if (isManager && !isAdmin) {
104	      // Managers can only see users with same licencees
105	      filteredUsers = filteredUsers.filter(user => {
106	        const userLicencees = Array.isArray(user.assignedLicencees)
107	          ? user.assignedLicencees
108	          : [];
109	        return userLicencees.some((userLic: string) =>
110	          currentUserLicencees.includes(userLic)
111	        );
112	      });
113	    } else if (isLocationAdmin) {
114	      // Location admins can only see users with matching locations
115	      const currentUserLocationPermissions = Array.isArray(
116	        (currentUser as { assignedLocations?: string[] })?.assignedLocations
117	      )
118	        ? (
119	            currentUser as { assignedLocations: string[] }
120	          ).assignedLocations.map((id: string) => String(id).trim())
121	        : [];
122	
123	      if (currentUserLocationPermissions.length === 0) {
124	        filteredUsers = [];
125	      } else {
126	        const currentUserId = currentUser._id ? String(currentUser._id) : null;
127	        filteredUsers = filteredUsers.filter(user => {
128	          const userId = user._id?.toString
129	            ? user._id.toString()
130	            : String(user._id);
131	          const isCurrentUser = currentUserId && userId === currentUserId;
132	
133	          if (isCurrentUser) {
134	            return true;
135	          }
136	
137	          const userLocationPermissions = Array.isArray(user.assignedLocations)
138	            ? user.assignedLocations.map((id: string) => String(id).trim())
139	            : [];
140	
141	          if (userLocationPermissions.length === 0) {
142	            return false;
143	          }
144	
145	          return userLocationPermissions.some((userLoc: string) =>
146	            currentUserLocationPermissions.includes(userLoc)
147	          );
148	        });
149	      }
150	    }
151	
152	    // ============================================================================
153	    // STEP 6: Apply licencee filter if provided
154	    // ============================================================================
155	    if (licencee && licencee !== 'all') {
156	      filteredUsers = filteredUsers.filter(user => {
157	        const userLicencees = Array.isArray(user.assignedLicencees)
158	          ? user.assignedLicencees
159	          : [];
160	        return userLicencees.includes(licencee);
161	      });
162	    }
163	
164	    // ============================================================================
165	    // STEP 7: Count users by role
166	    // ============================================================================
167	    // Note: Users can have multiple roles, so we count them in each role they have
168	    const counts = {
169	      total: filteredUsers.length,
170	      collectors: 0,
171	      admins: 0,
172	      locationAdmins: 0,
173	      managers: 0,
174	    };
175	
176	    filteredUsers.forEach(user => {
177	      const userRoles = (user.roles as string[]) || [];
178	      if (userRoles.includes('collector')) {
179	        counts.collectors++;
180	      }
181	      if (
182	        userRoles.includes('admin') ||
183	        userRoles.includes('developer') ||
184	        userRoles.includes('owner')
185	      ) {
186	        counts.admins++;
187	      }
188	      if (userRoles.includes('location admin')) {
189	        counts.locationAdmins++;
190	      }
191	      if (userRoles.includes('manager')) {
192	        counts.managers++;
193	      }
194	    });
195	
196	    // ============================================================================
197	    // STEP 8: Return counts
198	    // ============================================================================
199	    const duration = Date.now() - startTime;
200	    logRouteFetch(functionName, 'GET', '/api/users/counts', 1, user, duration);
201	
202	    return new Response(
203	      JSON.stringify({
204	        success: true,
205	        counts,
206	      }),
207	      {
208	        status: 200,
209	        headers: { 'Content-Type': 'application/json' },
210	      }
211	    );
212	  } catch (error) {
213	    const errorMessage =
214	      error instanceof Error ? error.message : 'Failed to fetch user counts';
215	    console.error('[USERS COUNTS API] Error:', error);
216	    logRouteError(functionName, 'GET', '/api/users/counts', errorMessage, user);
217	    return new Response(
218	      JSON.stringify({
219	        success: false,
220	        message: errorMessage,
221	      }),
222	      { status: 500 }
223	    );
224	  }
225	}
