2	 * Check Password API Route
3	 *
4	 * This route allows debounced checks to see if a provided password matches
5	 * a user's current password or history without performing a full update.
6	 * Used for real-time form validation.
7	 *
8	 * @module app/api/users/check-password/route
9	 */
10	
11	import { connectDB } from '@/app/api/lib/middleware/db';
12	import UserModel from '@/app/api/lib/models/user';
13	import { getUserIdFromServer } from '@/app/api/lib/helpers/users/users';
14	import { comparePassword } from '@/app/api/lib/utils/validation';
15	import { NextRequest, NextResponse } from 'next/server';
16	import {
17	  logRouteFetch,
18	  logRouteError,
19	  extractUserFromRequest,
20	} from '@/app/api/lib/utils/routeLogger';
21	
22	/**
23	 * Main POST handler for checking password matching
24	 *
25	 * @body {string} password - REQUIRED. The password string to check.
26	 * @body {string} type - REQUIRED. Check type: 'verify' (current) or 'reuse' (history).
27	 */
28	export async function POST(request: NextRequest) {
29	  const startTime = Date.now();
30	  const functionName = 'POST /api/users/check-password';
31	  const logUser = extractUserFromRequest(request);
32	
33	  try {
34	    // ============================================================================
35	    // STEP 1: Connect to DB and authenticate
36	    // ============================================================================
37	    await connectDB();
38	    const userId = await getUserIdFromServer();
39	    if (!userId) {
40	      logRouteError(
41	        functionName,
42	        'POST',
43	        '/api/users/check-password',
44	        'Unauthorized',
45	        logUser
46	      );
47	      return NextResponse.json(
48	        { success: false, message: 'Unauthorized' },
49	        { status: 401 }
50	      );
51	    }
52	
53	    // ============================================================================
54	    // STEP 2: Parse request
55	    // ============================================================================
56	    const { password, type } = await request.json();
57	    if (!password) {
58	      return NextResponse.json({ success: true, isMatch: false });
59	    }
60	
61	    // ============================================================================
62	    // STEP 3: Fetch user with password data
63	    // ============================================================================
64	    const trimmedPassword = password.trim();
65	    const user = await UserModel.findOne({ _id: userId }).select(
66	      '+password previousPasswords'
67	    );
68	
69	    if (!user) {
70	      console.log('[Check-Password] User not found for ID:', userId);
71	      logRouteError(
72	        functionName,
73	        'POST',
74	        '/api/users/check-password',
75	        'User not found',
76	        user
77	      );
78	      return NextResponse.json(
79	        { success: false, error: 'User not found' },
80	        { status: 404 }
81	      );
82	    }
83	
84	    // ============================================================================
85	    // STEP 4: Handle verify check
86	    // ============================================================================
87	    if (type === 'verify') {
88	      const isMatch = await comparePassword(
89	        trimmedPassword,
90	        user.password || ''
91	      );
92	      console.log('[Check-Password] Verification attempt:', {
93	        userId,
94	        passwordLength: trimmedPassword.length,
95	        hashLength: user.password?.length,
96	        isMatch,
97	      });
98	      return NextResponse.json({ success: true, isMatch });
99	    }
100	
101	    // ============================================================================
102	    // STEP 5: Handle reuse check
103	    // ============================================================================
104	    if (type === 'reuse') {
105	      // Check current
106	      const isSameAsCurrent = await comparePassword(
107	        password,
108	        user.password || ''
109	      );
110	      if (isSameAsCurrent) {
111	        return NextResponse.json({
112	          success: true,
113	          isReuse: true,
114	          reason: 'Same as current password',
115	        });
116	      }
117	
118	      // Check history
119	      if (user.previousPasswords && Array.isArray(user.previousPasswords)) {
120	        for (const prevHashed of user.previousPasswords) {
121	          if (await comparePassword(password, prevHashed)) {
122	            return NextResponse.json({
123	              success: true,
124	              isReuse: true,
125	              reason: 'Already used before',
126	            });
127	          }
128	        }
129	      }
130	
131	      return NextResponse.json({ success: true, isReuse: false });
132	    }
133	
134	    // ============================================================================
135	    // STEP 6: Handle invalid type
136	    // ============================================================================
137	    const duration = Date.now() - startTime;
138	    logRouteFetch(
139	      functionName,
140	      'POST',
141	      '/api/users/check-password',
142	      1,
143	      user,
144	      duration
145	    );
146	    return NextResponse.json(
147	      { success: false, message: 'Invalid check type' },
148	      { status: 400 }
149	    );
150	  } catch (error) {
151	    const errorMessage =
152	      error instanceof Error ? error.message : 'Unknown error';
153	    console.error('[Check Password API] Error:', error);
154	    logRouteError(
155	      functionName,
156	      'POST',
157	      '/api/users/check-password',
158	      errorMessage,
159	      logUser
160	    );
161	    return NextResponse.json(
162	      { success: false, message: 'Server error' },
163	      { status: 500 }
164	    );
165	  }
166	}
